// 合并两个 RSS Feed 的数据
const parseRSS = (xmlString, sourceName) => {
  const items = [];
  const itemRegex = /<item[^>]*>([\s\S]*?)<\/item>/g;
  let match;

  while ((match = itemRegex.exec(xmlString)) !== null) {
    const itemXml = match[1];

    const getTagContent = (tag) => {
      const regex = new RegExp(`<${tag}[^>]*>([\s\S]*?)<\/${tag}>`, 'i');
      const m = regex.exec(itemXml);
      return m ? m[1].replace(/<!\[CDATA\[|\]\]>/g, '').trim() : '';
    };

    items.push({
      title: getTagContent('title'),
      link: getTagContent('link'),
      summary: getTagContent('description').substring(0, 500),
      pub_date: getTagContent('pubDate'),
      source_name: sourceName
    });
  }

  return items;
};

const items = $input.all();
let allArticles = [];

for (const item of items) {
  const sourceName = item.json.node?.name || 'Unknown';
  const xmlContent = typeof item.json === 'string' ? item.json : item.json.data || '';
  const articles = parseRSS(xmlContent, sourceName);
  allArticles = allArticles.concat(articles);
}

return [{
  json: {
    articles: allArticles
  }
}];

// 检查当前时间是否是推送时间（8:55, 12:55, 19:55）
const now = new Date();
const hours = now.getHours();
const minutes = now.getMinutes();

// 推送时间点前5分钟触发
const pushTimes = [
  { hour: 8, min: 55 },
  { hour: 12, min: 55 },
  { hour: 19, min: 55 }
];

const shouldPush = pushTimes.some(t => hours === t.hour && minutes >= t.min && minutes < t.min + 5);

if (!shouldPush) {
  return []; // 不是推送时间，返回空数组停止工作流
}

// 获取文章并分批
const articles = $input.first().json.articles || [];
const batchSize = 15; // 每批15篇
const batches = [];

for (let i = 0; i < articles.length; i += batchSize) {
  batches.push(articles.slice(i, i + batchSize));
}

return batches.map((batch, index) => ({
  json: {
    batchIndex: index,
    articles: batch,
    totalBatches: batches.length,
    pushTime: `${hours}:${minutes}`
  }
}));

// 构建大模型筛选提示词
const batch = $input.first().json;
const articles = batch.articles;

// 读取关键词配置
const categories = [
  { name: "AIGC", keywords: ["生成式AI", "AIGC", "内容生成", "文生图", "文生视频", "AI绘画", "AI写作"] },
  { name: "AI初创", keywords: ["AI初创", "AI公司", "AI创业", "AI企业", "AI团队", "AI创业者"] },
  { name: "AI融资", keywords: ["AI融资", "AI投资", "AI估值", "AI IPO", "AI并购", "AI融资额", "AI投资人"] },
  { name: "大模型", keywords: ["大模型", "LLM", "GPT", "Claude", "Transformer", "BERT", "预训练模型"] },
  { name: "AI产品", keywords: ["AI产品", "AI应用", "AI工具", "AI助手", "AI Agent", "智能体", "AI软件"] }
];

// 构建文章列表文本
const articlesText = articles.map((a, i) => 
  `${i + 1}. 标题: ${a.title}\n   摘要: ${a.summary}\n   来源: ${a.source_name}`
).join('\n\n');

const prompt = `你是一位专业的 AI 领域内容筛选助手。

任务：判断以下文章是否与 AI 相关，并分类。

筛选规则（语义匹配，非关键词精确匹配）：
${categories.map(c => `- ${c.name}: ${c.description}（相关概念：${c.keywords.join('、')}）`).join('\n')}

待筛选文章：
${articlesText}

请输出 JSON 格式：
{\n  "results": [\n    {\n      "index": 1,\n      "title": "文章标题",\n      "relevant": true/false,\n      "categories": ["AI融资", "大模型"],\n      "reason": "简要说明匹配原因"\n    }\n  ]\n}`;

return [{
  json: {
    prompt: prompt,
    articles: articles,
    batchInfo: batch
  }
}];

// 解析 AI 响应并格式化推送内容
const aiResponse = $input.first().json;
const originalData = $input.first().json;

// 尝试解析 AI 返回的 JSON
let filterResults = [];
try {
  // 从 AI 响应中提取 JSON
  const content = aiResponse.content || aiResponse.text || JSON.stringify(aiResponse);
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    filterResults = parsed.results || [];
  }
} catch (e) {
  console.log('Parse error:', e);
}

// 获取相关文章
const articles = originalData.articles || [];
const relevantArticles = filterResults.filter(r => r.relevant).map(r => {
  const article = articles[r.index - 1];
  return {
    ...article,
    categories: r.categories || [],
    reason: r.reason || ''
  };
});

// 如果没有相关文章，返回空
if (relevantArticles.length === 0) {
  return [];
}

// 格式化 Markdown 消息
const now = new Date();
const dateStr = now.toLocaleDateString('zh-CN');
const timeStr = now.toLocaleTimeString('zh-CN', { hour: '2-digit', minute: '2-digit' });

let markdown = `## 📰 AI 资讯精选 (${dateStr} ${timeStr})\n\n`;
markdown += `本期筛选 **${articles.length}** 篇文章，命中 **${relevantArticles.length}** 篇\n\n---\n\n`;

relevantArticles.forEach((article, index) => {
  markdown += `### ${index + 1}. ${article.title}\n`;
  markdown += `**分类**: ${article.categories.join(' | ')}\n`;
  markdown += `**公众号**: ${article.source_name}\n`;
  markdown += `**摘要**: ${article.summary.substring(0, 100)}...\n`;
  markdown += `[阅读原文](${article.link || '#'})\n\n---\n\n`;
});

markdown += `*Powered by n8n + 大模型筛选*`;

return [{
  json: {
    msgtype: 'markdown',
    markdown: {
      content: markdown
    }
  }
}];
